# OEIS sequence: A394660

from heapq import heappop, heappush
from sympy import prime, isprime
def A394660(n):
    h, hset, p = [1], {1}, prime(n)
    while True:
        if len(h)==0:
            return 0
        a = heappop(h)
        if isprime(p-a):
            return p-a
        for q in (2,3):
            m = a*q
            if m not in hset:
                heappush(h,m)
                hset.add(m) # _Chai Wah Wu_, Apr 15 2026

